#!/usr/bin/env node
/**
 * CLI entry point for the refactored coding agent.
 * Uses main.ts with AgentSession and new mode modules.
 *
 * Test with: npx tsx src/cli-new.ts [args...]
 */
process.title = "pi";
process.emitWarning = (() => { });
import { EnvHttpProxyAgent, setGlobalDispatcher } from "undici";
import { main } from "./main.js";
setGlobalDispatcher(new EnvHttpProxyAgent());
main(process.argv.slice(2));
//# sourceMappingURL=cli.js.map

import { IconArrowDownRight, IconArrowUpRight } from "@dfp/react-icons";

import { useTT } from "../../useTT.ts";
import { CashflowTableValueCell } from "./components/CashflowTableValueCell.tsx";
import {
  CashflowCategory,
  CashflowCategoryDataRow,
  CashflowCategoryHeader,
  CashflowCategoryHeaderIcon,
  CashflowCategoryHeaderTitle,
  CashflowCategoryRows,
  CashflowCategoryTrigger,
  useCashflowTable,
} from "./components/index.ts";
import type { CategoryType } from "./types/index.ts";

type CashflowTableCategorySectionProps = {
  variant: "income" | "costs";
};

const sectionPresets = {
  income: {
    titleKey: "cashflowTable.rows.income" as const,
    icon: IconArrowUpRight,
    iconColor: "success.main",
    categoryType: "income" as const,
    direction: "IN" as const,
    totalSelector: (period: { income: number }) => period.income,
    filterSelector: (categoryFilter: { income: CategoryType[] }) =>
      categoryFilter.income,
  },
  costs: {
    titleKey: "cashflowTable.rows.costs" as const,
    icon: IconArrowDownRight,
    iconColor: "error.main",
    categoryType: "costs" as const,
    direction: "OUT" as const,
    totalSelector: (period: { costs: number }) => period.costs,
    filterSelector: (categoryFilter: { costs: CategoryType[] }) =>
      categoryFilter.costs,
  },
};

export function CashflowTableCategorySection({
  variant,
}: CashflowTableCategorySectionProps) {
  const { data, categoryFilter, allCategories } = useCashflowTable();
  const { tt } = useTT();
  const preset = sectionPresets[variant];
  const Icon = preset.icon;

  return (
    <CashflowCategory>
      <CashflowCategoryHeader>
        <CashflowCategoryHeaderTitle>
          <CashflowCategoryHeaderIcon sx={{ color: preset.iconColor }}>
            <Icon />
          </CashflowCategoryHeaderIcon>
          {tt(preset.titleKey)}
          <CashflowCategoryTrigger categoryType={preset.categoryType} />
        </CashflowCategoryHeaderTitle>

        {data?.periods.map((period, index) => (
          <CashflowTableValueCell
            key={period.id}
            columnIndex={index}
            dateFrom={period.dateFrom}
            isBold
          >
            {preset.totalSelector(period)}
          </CashflowTableValueCell>
        ))}
      </CashflowCategoryHeader>

      <CashflowCategoryRows>
        {preset.filterSelector(categoryFilter).map((category: CategoryType) => (
          <CashflowCategoryDataRow
            key={category}
            allCategories={allCategories}
            category={category}
            direction={preset.direction}
          />
        ))}
      </CashflowCategoryRows>
    </CashflowCategory>
  );
}

import {
  Box,
  IconButton,
  SxProps,
  TableCell,
  TableRow,
  Theme,
  Tooltip,
} from "@mui/material";
import { type ReactNode, useCallback, useState } from "react";

import type { TransactionDirection } from "@dfp/bw-isomorphic-enums";
import { IconChevronDown } from "@dfp/react-icons";
import { createCheckedContext } from "@dfp/react-utils";

import { useTT } from "../../../useTT.ts";
import { useSelectedColumn } from "../../SelectionContext.tsx";
import { cashflowLayoutConfig } from "../../cashflow-layout.config.ts";
import type { CategoryType } from "../types/index.ts";
import { useOpenCategoryDetail } from "./categoryDetail/index.ts";

type CashflowCategoryContextValue = {
  isExpanded: boolean;
  toggleExpanded: () => void;
};

const [CashflowCategoryProvider, useCashflowCategory] =
  createCheckedContext<CashflowCategoryContextValue>("CashflowCategoryContext");

type CashflowCategoryProps = {
  children: ReactNode;
  defaultExpanded?: boolean;
};

export function CashflowCategory({
  children,
  defaultExpanded = true,
}: CashflowCategoryProps) {
  const [isExpanded, setIsExpanded] = useState(defaultExpanded);

  const toggleExpanded = () => setIsExpanded((prev) => !prev);

  return (
    <CashflowCategoryProvider value={{ isExpanded, toggleExpanded }}>
      {children}
    </CashflowCategoryProvider>
  );
}

type CashflowCategoryHeaderProps = {
  children: ReactNode;
};

export function CashflowCategoryHeader({
  children,
}: CashflowCategoryHeaderProps) {
  return <TableRow>{children}</TableRow>;
}

type CashflowCategoryHeaderTitleProps = {
  children: ReactNode;
};

export function CashflowCategoryHeaderTitle({
  children,
}: CashflowCategoryHeaderTitleProps) {
  return (
    <TableCell
      sx={{
        backgroundColor: "background.paper",
        borderRight: 1,
        borderRightColor: "custom.borderSecondary",
        fontWeight: 600,
        width: cashflowLayoutConfig.labelColumnWidth,
        boxSizing: "border-box",
      }}
    >
      <Box sx={{ display: "flex", alignItems: "center", gap: 1 }}>
        {children}
      </Box>
    </TableCell>
  );
}

type CashflowCategoryHeaderIconProps = {
  children: ReactNode;
  sx: SxProps<Theme>;
};

export function CashflowCategoryHeaderIcon({
  children,
  sx,
}: CashflowCategoryHeaderIconProps) {
  return (
    <Box
      component="span"
      sx={{
        fontSize: "1.2em",
        ...sx,
      }}
    >
      {children}
    </Box>
  );
}

type CashflowCategoryRowProps = {
  children: ReactNode;
};

export function CashflowCategoryRow({ children }: CashflowCategoryRowProps) {
  return <TableRow>{children}</TableRow>;
}

type CashflowCategoryRowLabelProps = {
  children: ReactNode;
  category: CategoryType;
  direction: TransactionDirection;
};

export function CashflowCategoryRowLabel({
  children,
  category,
  direction,
}: CashflowCategoryRowLabelProps) {
  const selectedColumn = useSelectedColumn();

  const openDetail = useOpenCategoryDetail({
    category,
    direction,
    categoryLabel: children,
  });

  const handleClick = useCallback(() => {
    if (selectedColumn == null) return;
    openDetail(selectedColumn);
  }, [selectedColumn, openDetail]);

  return (
    <TableCell
      onClick={handleClick}
      sx={{
        backgroundColor: "background.paper",
        borderRight: 1,
        borderRightColor: "custom.borderSecondary",
        paddingLeft: 4,
        width: cashflowLayoutConfig.labelColumnWidth,
        minWidth: cashflowLayoutConfig.labelColumnWidth,
        maxWidth: cashflowLayoutConfig.labelColumnWidth,
        boxSizing: "border-box",
        cursor: "pointer",
      }}
    >
      <Tooltip title={children} placement="top-start">
        <Box
          component="span"
          sx={{
            display: "block",
            overflow: "hidden",
            textOverflow: "ellipsis",
            whiteSpace: "nowrap",
            "&:hover": {
              textDecoration: "underline",
            },
          }}
        >
          {children}
        </Box>
      </Tooltip>
    </TableCell>
  );
}

type CashflowCategoryTriggerProps = {
  categoryType: "income" | "costs";
};

export function CashflowCategoryTrigger({
  categoryType,
}: CashflowCategoryTriggerProps) {
  const { isExpanded, toggleExpanded } = useCashflowCategory();
  const { tt } = useTT();

  const ariaLabel = isExpanded
    ? tt(
        categoryType === "income"
          ? "cashflowTable.accessibility.collapseIncome"
          : "cashflowTable.accessibility.collapseCosts",
      )
    : tt(
        categoryType === "income"
          ? "cashflowTable.accessibility.expandIncome"
          : "cashflowTable.accessibility.expandCosts",
      );

  return (
    <IconButton
      size="small"
      onClick={toggleExpanded}
      aria-expanded={isExpanded}
      aria-label={ariaLabel}
      sx={{
        ml: "auto",
        transform: isExpanded ? "rotate(180deg)" : "rotate(0deg)",
        transition: "transform 0.2s",
      }}
    >
      <IconChevronDown />
    </IconButton>
  );
}

type CashflowCategoryRowsProps = {
  children: ReactNode;
};

export function CashflowCategoryRows({ children }: CashflowCategoryRowsProps) {
  const { isExpanded } = useCashflowCategory();

  return isExpanded ? <>{children}</> : null;
}

import type { TransactionDirection } from "@dfp/bw-isomorphic-enums";

import { CashflowTableCell } from "../CashflowTableCell.tsx";
import type {
  CashflowPeriod,
  CategoryOption,
  CategoryType,
} from "../types/index.ts";
import { getCategoryLabel } from "../utils/index.ts";
import {
  CashflowCategoryRow,
  CashflowCategoryRowLabel,
} from "./CashflowCategory.tsx";
import { useCashflowTable } from "./CashflowTableContext.tsx";
import { useOpenCategoryDetail } from "./categoryDetail/index.ts";

type CashflowCategoryDataRowProps = {
  allCategories: Array<CategoryOption>;
  category: CategoryType;
  direction: TransactionDirection;
};

export function CashflowCategoryDataRow({
  allCategories,
  category,
  direction,
}: CashflowCategoryDataRowProps) {
  const { data } = useCashflowTable();
  const categoryLabel = getCategoryLabel(category, allCategories);

  const openDetail = useOpenCategoryDetail({
    category,
    direction,
    categoryLabel,
  });

  const getCategoryValue = (period: CashflowPeriod) =>
    (direction === "IN" ? period.incomeCategories : period.costsCategories).get(
      category,
    ) ?? 0;

  return (
    <CashflowCategoryRow>
      <CashflowCategoryRowLabel category={category} direction={direction}>
        {categoryLabel}
      </CashflowCategoryRowLabel>

      {data?.periods.map((period, index) => (
        <CashflowTableCell
          key={period.id}
          value={getCategoryValue(period)}
          columnIndex={index}
          dateFrom={period.dateFrom}
          colorMode="none"
          onClick={() => openDetail(index)}
        />
      ))}
    </CashflowCategoryRow>
  );
}

import { TableCell, TableRow } from "@mui/material";
import { ReactNode } from "react";

import { cashflowLayoutConfig } from "../../cashflow-layout.config.ts";

type CashflowTableSummaryRowProps = {
  children: ReactNode;
};

export function CashflowTableSummaryRow({
  children,
}: CashflowTableSummaryRowProps) {
  return <TableRow>{children}</TableRow>;
}

type CashflowTableSummaryRowLabelProps = {
  children: ReactNode;
};

export function CashflowTableSummaryRowLabel({
  children,
}: CashflowTableSummaryRowLabelProps) {
  return (
    <TableCell
      sx={{
        backgroundColor: "background.paper",
        borderRight: 1,
        borderRightColor: "custom.borderSecondary",
        fontWeight: 600,
        width: cashflowLayoutConfig.labelColumnWidth,
        boxSizing: "border-box",
      }}
    >
      {children}
    </TableCell>
  );
}

import { Box } from "@mui/material";
import { memo } from "react";

import { CurrencyAmount } from "@dfp/react-currency-amount";

import { CashflowQualityIndicator } from "../../chart/components/CashflowQualityIndicator.tsx";
import type { BalanceQuality } from "../../types/cashflow.types.ts";
import {
  CashflowTableValueCell,
  type CashflowTableValueColorMode,
} from "./CashflowTableValueCell.tsx";

export type CashflowTableSummaryValueCellProps = {
  value: number | null;
  currency: string;
  columnIndex: number;
  dateFrom: string;
  isBold?: boolean;
  colorMode?: CashflowTableValueColorMode;
  balanceQuality?: BalanceQuality | null;
  onClick?: () => void;
};

function CashflowTableSummaryValueCellComponent({
  value,
  currency,
  columnIndex,
  dateFrom,
  isBold = false,
  colorMode,
  balanceQuality,
  onClick,
}: CashflowTableSummaryValueCellProps) {
  return (
    <CashflowTableValueCell
      columnIndex={columnIndex}
      dateFrom={dateFrom}
      isBold={isBold}
      colorMode={colorMode}
      onClick={onClick}
      color={value === null ? "text.primary" : undefined}
    >
      <Box
        sx={{
          minHeight: 24,
          display: "flex",
          alignItems: "center",
          justifyContent: "flex-end",
          gap: 0.5,
          width: "100%",
          whiteSpace: "nowrap",
        }}
      >
        {value !== null ? (
          <>
            <CashflowQualityIndicator
              balanceQuality={balanceQuality}
              size="sm"
              variant="icon"
            />
            <CurrencyAmount
              notation="compact"
              value={value}
              currency={currency}
              naturalPrecision
            />
          </>
        ) : null}
      </Box>
    </CashflowTableValueCell>
  );
}

export const CashflowTableSummaryValueCell = memo(
  CashflowTableSummaryValueCellComponent,
);
CashflowTableSummaryValueCell.displayName = "CashflowTableSummaryValueCell";

import { useTT } from "../../useTT.ts";
import { CashflowTableCell } from "./CashflowTableCell.tsx";
import {
  CashflowTableSummaryRow,
  CashflowTableSummaryRowLabel,
  useCashflowTable,
